import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailChannelHandler,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    service = new NotificationService(eventBus);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });
  });

  describe('notification management', () => {
    it('should count notifications', () => {
      expect(service.getNotificationCount()).toBe(0);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });

  describe('EventBus-based notification dispatch', () => {
    it('should publish notification:requested events via EventBus', async () => {
      service.sendNotification({
        recipient: 'bob@example.com',
        subject: 'Test Subject',
        body: 'Test body content',
      });

      const eventLog = eventBus.getEventLog();
      const notifEvents = eventLog.filter((e) => e.type === 'notification:requested');
      expect(notifEvents).toHaveLength(1);
      expect(notifEvents[0]).toMatchObject({
        type: 'notification:requested',
        recipient: 'bob@example.com',
        subject: 'Test Subject',
        body: 'Test body content',
        channel: 'email',
      });
    });

    it('should default channel to email', () => {
      service.sendNotification({
        recipient: 'alice@example.com',
        subject: 'Hello',
        body: 'World',
      });

      const eventLog = eventBus.getEventLog();
      const notifEvent = eventLog.find((e) => e.type === 'notification:requested');
      expect(notifEvent).toBeDefined();
      if (notifEvent?.type === 'notification:requested') {
        expect(notifEvent.channel).toBe('email');
      }
    });

    it('should allow specifying a custom channel', () => {
      service.sendNotification({
        recipient: 'alice@example.com',
        subject: 'Hello',
        body: 'World',
        channel: 'sms',
      });

      const eventLog = eventBus.getEventLog();
      const notifEvent = eventLog.find((e) => e.type === 'notification:requested');
      expect(notifEvent).toBeDefined();
      if (notifEvent?.type === 'notification:requested') {
        expect(notifEvent.channel).toBe('sms');
      }
    });
  });
});

describe('EmailChannelHandler', () => {
  let eventBus: EventBus;
  let emailHandler: EmailChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    emailHandler = new EmailChannelHandler(eventBus);
    resetNotificationIdCounter();
  });

  it('should deliver email notifications from EventBus', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Welcome to TaskFlow Pro!',
      channel: 'email',
      timestamp: new Date(),
    });

    const delivered = emailHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('alice@example.com');
    expect(delivered[0]?.subject).toBe('Welcome');
    expect(delivered[0]?.body).toBe('Welcome to TaskFlow Pro!');
    expect(delivered[0]?.channel).toBe('email');
  });

  it('should ignore notifications for other channels', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alice@example.com',
      subject: 'SMS Alert',
      body: 'This is an SMS',
      channel: 'sms',
      timestamp: new Date(),
    });

    const delivered = emailHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(0);
  });

  it('should handle multiple notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alice@example.com',
      subject: 'First',
      body: 'First email',
      channel: 'email',
      timestamp: new Date(),
    });
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'bob@example.com',
      subject: 'Second',
      body: 'Second email',
      channel: 'email',
      timestamp: new Date(),
    });

    const delivered = emailHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(2);
    expect(delivered[0]?.recipient).toBe('alice@example.com');
    expect(delivered[1]?.recipient).toBe('bob@example.com');
  });

  it('should generate sequential IDs for delivered notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alice@example.com',
      subject: 'First',
      body: 'First',
      channel: 'email',
      timestamp: new Date(),
    });
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'bob@example.com',
      subject: 'Second',
      body: 'Second',
      channel: 'email',
      timestamp: new Date(),
    });

    const delivered = emailHandler.getDeliveredNotifications();
    expect(delivered[0]?.id).toBe('notif-0001');
    expect(delivered[1]?.id).toBe('notif-0002');
  });

  it('should work end-to-end with NotificationService', async () => {
    statusChangeCallbacks.clear();
    const service = new NotificationService(eventBus);
    // EmailChannelHandler is already subscribed to this eventBus

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 15 },
        ],
        total: 45,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // NotificationService should have the notification
    expect(service.getNotificationCount()).toBe(1);

    // EmailChannelHandler should have delivered it
    const delivered = emailHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('alice@example.com');
    expect(delivered[0]?.subject).toContain('Order Confirmation');
  });
});

